$out="-- BCSS Form 1 - Second Term Marks (Sequences 3 & 4)\nUSE saint_academia;\n";
$out.="SET @school_id:=(SELECT id FROM schools WHERE name LIKE '%Baptist%' LIMIT 1);\n";
$out.="SET @year_id:=(SELECT id FROM academic_years WHERE school_id=@school_id AND label='2025/2026' LIMIT 1);\n";
$out.="SET @term_id:=(SELECT id FROM terms WHERE academic_year_id=@year_id AND term_number=2 LIMIT 1);\n";
$out.="SET @class_id:=(SELECT id FROM classes WHERE school_id=@school_id AND academic_year_id=@year_id AND name='Form 1' LIMIT 1);\n";
foreach($codes as $c){$out.="SET @s_".strtolower($c).":=(SELECT id FROM subjects WHERE school_id=@school_id AND code='$c' LIMIT 1);\n";}
$seen=[];
foreach($t2 as [$reg,$marks]){
    if(isset($seen[$reg]))continue;$seen[$reg]=true;
    $var='st'.substr($reg,4);
    $out.="\n-- $reg\nSET @$var:=(SELECT id FROM students WHERE school_id=@school_id AND student_number='$reg' LIMIT 1);\n";
    $rows=[];
    foreach($marks as $code=>[$s3,$s4]){
        $sv='@s_'.strtolower($code);
        foreach([[$s3,3],[$s4,4]] as [$sc,$sq]){
            $g=grade($sc);$r=rmk($sc);
            $rows[]="(@school_id,@$var,$sv,@class_id,@term_id,'SE',$sc,20,'$g','$r',$sq,NOW())";
        }
    }
    $out.="INSERT INTO exam_results(school_id,student_id,subject_id,class_id,term_id,exam_type,score,max_score,grade,remarks,sequence,created_at) VALUES\n";
    $out.=implode(",\n",$rows)."\nON DUPLICATE KEY UPDATE score=VALUES(score),grade=VALUES(grade),remarks=VALUES(remarks);\n";
}
$out.="\nSELECT 'Second Term marks inserted.' AS status;\n";
file_put_contents('database/migrations/007_bcss_term2_marks.sql',$out);
